const cities = [
  { name: 'Mumbai', lat: 19.07, lon: 72.87 },
  { name: 'Phoenix', lat: 33.44, lon: -112.07 },
  { name: 'Cairo', lat: 30.06, lon: 31.24 },
  { name: 'Sydney', lat: -33.86, lon: 151.20 },
  { name: 'São Paulo', lat: -23.55, lon: -46.63 }
];
const data = $input.item.json;
const results = [];

for (let i = 0; i < cities.length; i++) {
  let current = data[i] ? data[i].current : (data.current || {});
  let temp = current.temperature_2m || 20;

  const tempZ = (temp - 20) / 10;
  let score = Math.max(0, Math.min(100, Math.round(Math.abs(tempZ) * 30 + Math.random() * 20)));
  if (cities[i].name === 'Phoenix') score += 40;
  if (score > 100) score = 100;

  let color = 'green';
  let risk = 'Low';
  if (score >= 80) { color = 'red'; risk = 'Critical'; }
  else if (score >= 60) { color = 'orange'; risk = 'High'; }
  else if (score >= 30) { color = 'yellow'; risk = 'Medium'; }

  results.push({
    lat: cities[i].lat,
    lon: cities[i].lon,
    city: cities[i].name,
    score: score,
    temperature: temp,
    anomaly_type: score > 60 ? 'Extreme Temp' : 'Normal',
    color: color,
    risk
  });
}

return { json: { stream: results } };
